nav_platform:"Plattform",nav_modules:"Module",nav_proces:"So funktioniert\u2019s",nav_projecten:"Projekte",nav_usps:"Warum wir",nav_infra:"Infrastruktur",nav_contact:"Kontakt",
hero_h1:'25 KI-Agents. Eine Plattform.<br><span>Keine Kompromisse.</span>',
hero_p:"Die komplette KI-Plattform f\u00fcr touristische Destinationen. Von Website bis Chatbot, von Content bis Commerce \u2014 vollautomatisiert, mehrsprachig und lokal.",
hero_cta1:"Demo anfragen",hero_cta2:"Plattform entdecken \u2193",
badge_eu:"EU-First",badge_eu_d:"Alle Daten, KI und Infrastruktur innerhalb der EU",
badge_wl:"White Label",badge_wl_d:"Eigene Marke, Domain und Farbpalette",
badge_l2l:"Local2Local",badge_l2l_d:"Lokales Wissen von Einheimischen f\u00fcr Einheimische",
badge_mt:"Multi-Tenancy",badge_mt_d:"Eine Plattform, unbegrenzte Destinationen",
plat_label:"Die Plattform",plat_title:"KI-gesteuert. Menschlich kontrolliert.",
plat_sub:"HolidaiButler verbindet k\u00fcnstliche Intelligenz mit menschlicher Expertise. Jede Empfehlung, jeder Inhalt und jede Interaktion wird von KI gesteuert \u2014 aber stets von Menschen kontrolliert und validiert. Keine Blackbox, sondern transparente Technologie im Dienst des Nutzers.",
plat_c1_t:"Hyper-personalisiert",plat_c1_d:"Echtzeit-Empfehlungen basierend auf Profil, Vorlieben, Standort, Wetter und Uhrzeit. Keine generischen Tipps \u2014 immer relevant, immer pers\u00f6nlich.",
plat_c2_t:"Local2Local",plat_c2_d:"Lokale Partnerschaften, die die lokale Wirtschaft und Identit\u00e4t unterst\u00fctzen. Keine anonyme Plattform, sondern eine Br\u00fccke zwischen Besuchern und der Gemeinschaft.",
plat_c3_t:"Europ\u00e4ische Compliance als St\u00e4rke",plat_c3_d:"RaaS \u2014 Regulation as a Service. DSGVO, EU AI Act, PCI DSS Compliance in die Plattform integriert. Vertrauensw\u00fcrdig und sicher von Daten bis Zahlung.",
mod_label:"Module",mod_title:"Enterprise-grade. Modular. Skalierbar.",mod_sub:"Jede Komponente ist unabh\u00e4ngig einsetzbar und vollst\u00e4ndig integriert. Aktivieren Sie nur, was Sie brauchen.",
mod1_t:"POI Management",mod1_d:"Unbegrenzte Anzahl POIs mit 80+ Datenfeldern pro Standort, automatisierte Qualit\u00e4ts- und Aktualit\u00e4tskontrolle, Tier-Management.",
mod2_t:"Agenda & Events",mod2_d:"Veranstaltungskalender mit automatischer Kategorisierung, mehrsprachiger Darstellung und Integration lokaler und internationaler Datenquellen.",
mod3_t:"PubliQio Content Studio",mod3_d:"KI-gesteuerte Content-Generierung mit Tone-of-Voice pro Marke, SEO-Optimierung, Multi-Plattform-Publikation und Performance-Tracking. Als Standalone-Produkt verf\u00fcgbar.",
mod4_t:"HoliBot KI-Chatbot",mod4_d:"Mehrsprachiger RAG-Chatbot mit POI-Wissen, Routenplanung und Buchungsintegration. Pers\u00f6nliche lokale Empfehlungen rund um die Uhr.",
mod5_t:"Website Page Builder",mod5_d:"Konfigurieren und ver\u00f6ffentlichen Sie eine komplette Destinations-Website ohne Code. 35+ Bl\u00f6cke, visuelle Editoren, Live-Vorschau, Drag-and-Drop, Tenant-Theming und Server-Side Rendering f\u00fcr optimales SEO.",
mod6_t:"Commerce & Ticketing",mod6_d:"Ticketverkauf und Reservierungen mit Adyen-Zahlungen, QR-Validierung, Bestandsverwaltung und automatisierter Abrechnung pro Partner.",
mod7_t:"Mehrsprachigkeit",mod7_d:"\u00dcbersetzen Sie mit unerreichter Genauigkeit in 100+ Sprachen mit einem Klick. DeepL Pro + Mistral AI. Konfigurierbare Sprachsets pro Destination.",
mod8_t:"Analytics & Monitoring",mod8_d:"25 KI-Agents \u00fcberwachen kontinuierlich Datenqualit\u00e4t, Performance und Verf\u00fcgbarkeit. SimpleAnalytics f\u00fcr datenschutzfreundliches Website-Tracking.",
mod9_t:"Multi-Tenant-Architektur",mod9_d:"Eine Installation, unbegrenzte Destinationen. Jede mit eigener Domain, Branding, Sprachset, Content und Benutzerverwaltung.",
stat1:"API-Endpunkte",stat2:"Sprachen",stat3:"Page Builder Bl\u00f6cke",stat4:"KI-Agents",stat5:"Plattform",
